let documentId = null;
let formattedTheme = null;
let summaries = null;

/**
 * Recursively walk the entire object tree
 * and collect document, formatted_theme, and summaries
 */
function walk(obj) {
  if (!obj || typeof obj !== 'object') return;

  if (obj.document && !documentId) {
    documentId = obj.document;
  }

  if (obj.formatted_theme && !formattedTheme) {
    formattedTheme = obj.formatted_theme;
  }

  if (obj.summaries && !summaries) {
    summaries = obj.summaries;
  }

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    if (Array.isArray(value)) {
      value.forEach(walk);
    } else if (typeof value === 'object') {
      walk(value);
    }
  }
}

// 1. Workflow Initiated path
try {
  const items = $('Workflow Initiated').all();
  if (items.length > 0) {
    walk(items[0].json);
  }
} catch (e) {
  console.error('Workflow Initiated error:', e);
}

// 2. Chat-trigger fallback
if (!documentId || !formattedTheme || !summaries) {
  try {
    const chatInput = $('When a chat message received').first().json.chatInput;
    if (chatInput) {
      const parsed = JSON.parse(chatInput);
      walk(parsed);
    }
  } catch (e) {
    console.error('Chat-trigger error:', e);
  }
}

// 3. Guards
if (!documentId) {
  throw new Error('Document ID not found in any input');
}

if (!formattedTheme) {
  throw new Error('formatted_theme not found in any input');
}

if (!summaries) {
  throw new Error('summaries not found in any input');
}

// 4. Output
return [
  {
    json: {
      inputData: documentId,
      formatted_theme: formattedTheme,
      summaries: summaries
    }
  }
];

// Fetch the formatted_theme from your HTML document node
const formattedTheme = $('Fetch HTML Document ID').first().json.formatted_theme;

// Fetch the newsletter HTML content from the input node
const content = $input.first().json.content;

// Combine into a single object
return {
  json: {
    newsletter: {
      formattedTheme,
      content
    }
  }
};

const rawText = $input.first().json.output.data;
const MIN_CHARS = 265;
const MAX_CHARS = 315;
let errors = [];

// Regex to find each Body block inside slides
const bodyRegex =
  /(\*Body:\*\n)([\s\S]*?)(?=\n\n---|\n\n\*Slide|\s*$)/g;

const updatedText = rawText.replace(bodyRegex, (match, bodyLabel, bodyContent) => {
  // Preserve paragraph breaks but normalize excess whitespace
  const cleanedBody = bodyContent.trimEnd();

  // Character count includes spaces and line breaks
  const charCount = (cleanedBody.length) - 4;

  // Log error if character count is outside range
  if (charCount < MIN_CHARS || charCount > MAX_CHARS) {
    errors.push({
      slide_body: bodyContent,
      type: "CHARACTER_LIMIT_VIOLATION",
      severity: "ERROR",
      actualCharacters: charCount,
      requiredRange: `${MIN_CHARS}-${MAX_CHARS}`,
      instruction:
        "Rewrite the slide body to be 265–315 characters total while preserving meaning, tone, and structure."
    });
  }

  return (
    `${bodyLabel}` +
    `${cleanedBody}\n\n` +
    `*Character count:* ${charCount} characters`
  );
});

const staticData = $getWorkflowStaticData('node');
const execId = $execution.id;
// Initialize run counter if not present
if (!staticData[execId]) {
  staticData[execId] = 0;
}
// Increment the run count
staticData[execId] += 1;
const MAX_ATTEMPTS = 2;
if (staticData[execId] >= MAX_ATTEMPTS) {
  errors = [];
}

return [
  {
    json: {
      output: updatedText,
      character_errors: errors
    }
  }
];

// Fetch the first item from the previous node called 'Code in JavaScript'
const prevOutput = $('Code in JavaScript').first().json.output;
const charErrors = $('Code in JavaScript').first().json.character_errors;

// Wrap into a single JSON object
return [
  {
    json: {
      generated: {
        output: prevOutput,
        character_errors: charErrors
      }
    }
  }
];

let output;

try {
  // Try fetching regenerated output
  output = $('Re-Generate Linkedin Carousel using LLM').first().json.output.data;

  if (!output) {
    throw new Error('Re-generator output is empty');
  }
} catch (e) {
  // Fallback to original generator output
  output = $('Code in JavaScript').first().json.output;
}

return [
  {
    json: {
      output
    }
  }
];
